  const provenanceCore = {
    result_kind: minimal.result_kind,
    evidence_required: minimal.evidence_required,
    origin_realm: minimal.origin_realm,
    origin_route: minimal.origin_route,
    source: minimal.source,
    source_family: minimal.source_family,
    title: capText(minimal.title || "", 200),
    document_cache_key: minimal.document_cache_key,
    source_ref: minimal.source_ref,
    result_ref: minimal.result_ref,
    final_rank: minimal.final_rank,
    topicality_tier: minimal.topicality_tier,
    topicality_factor: minimal.topicality_factor,
    topicality_signals: minimal.topicality_signals,
    weighted_rrf_score: minimal.weighted_rrf_score,
    unified_rank_score: minimal.unified_rank_score,
    production_fusion_applied: minimal.production_fusion_applied,
    ranking_policy: minimal.ranking_policy,
    cross_source_merged: minimal.cross_source_merged,
    merged_representation_count: minimal.merged_representation_count,
    dedup_action: minimal.dedup_action ?? null,
    duplicate_suspicion: minimal.duplicate_suspicion ?? null
  };
  const provenanceRaw = JSON.stringify(provenanceCore);
  if (provenanceRaw.length <= maxPayloadChars) return provenanceRaw;
