  "hybrid_search_enabled", "match_sources", "fusion_sources", "branch_ranks", "branch_scores", "hybrid_rrf_score",
  "hybrid_primary_score", "hybrid_rank_score", "merged_from_count", "merged_range_start", "merged_range_end",
  "vector_branch_status", "lexical_branch_status", "weighted_rrf_score", "rrf_branch_contributions",
  "production_fusion_applied", "cross_source_merged", "topicality_signals", "ranking_policy", "score_metadata_ranked",
  "dedup_confidence", "dedup_reason", "session_dedup_group_key", "duplicate_suspicion", "duplicate_suspicion_confidence",
  "duplicate_suspicion_strength", "duplicate_suspicion_reason", "duplicate_suspicion_stage", "duplicate_suspicion_signals",
  // marker HK (F4) — suspected_duplicate_of + duplicate_recheck_required_on_read are deliberately NOT listed here:
  // they are small and directly actionable (gpt_guide.duplicate_reuse tells the GPT to reuse the cached copy /
  // score with scoreReadEvidenceWithContext), so they stay on the wire even with dev-mode off.
  "duplicate_recheck_trigger", "duplicate_recheck_context",
  "semantic_rank", "preview_status", "vector_match_id", "vector_segment_key", "vector_id", "vector_status",
