  "cache_read_update", "owner_score", "document_text_state", "served_from", "resolved_from",
  "requested_limit", "effective_limit", "limit_clamped", "max_limit",
  "requested_read_limit", "effective_read_limit", "read_limit_clamped", "max_read_limit",
