  // marker HG — score-read-evidence registry/promotion/vector-routing internals (the GPT keeps: score_status,
  // value_score, owner_key/owner_type, owner_apply_status, read_event_id, is_english, warning)
  "updated_owner", "duplicate_recheck", "desired_vector_model_role", "desired_vector_index_key",
  "vector_transition_needed", "language_signal_source", "language_signal_status", "language_signal_errors",
  "promotion_blocked_reason", "cache_write_action", "vector_cleanup_recommended",
  // marker HH — memory-search top-level engine telemetry (the GPT keeps: count, results, note-free core, gpt_guide)
  "search_function", "resolved_adapter", "memory_search_mode", "vector_used", "memory_vector_status",
  "memory_vector_branch", "vector_status", "scanned_segments_before_hygiene", "scanned_segments",
